-- Seed data for the Gan Nuna Banuna pilot.
-- Safe to run after 0001 and 0002. Uses fixed UUIDs and ON CONFLICT so it is idempotent.
-- Profiles (teacher/parent) are linked separately AFTER you create the auth users
-- (see docs/12-supabase-setup.md, "Link pilot users").

-- Daycare ------------------------------------------------------------------
values ('11111111-1111-1111-1111-111111111111', 'nuna-banuna', 'גן נונה בנונה')
on conflict (id) do nothing;

-- Children -----------------------------------------------------------------
on conflict (id) do nothing;

-- Guardians ----------------------------------------------------------------
on conflict (id) do nothing;

-- Child <-> guardian links -------------------------------------------------
on conflict (child_id, guardian_id) do nothing;

-- Attendance for today -----------------------------------------------------
on conflict (child_id, attendance_date) do nothing;

-- Contracts ----------------------------------------------------------------
on conflict (id) do nothing;

-- Daily report for today ---------------------------------------------------
values ('d0000000-0000-0000-0000-000000000001', '11111111-1111-1111-1111-111111111111', current_date, 'סיכום יום')
on conflict (daycare_id, report_date) do nothing;

on conflict (id) do nothing;

on conflict (id) do nothing;

on conflict (id) do nothing;

-- Messaging (sender null = from the daycare) -------------------------------
values ('e0000000-0000-0000-0000-000000000001', '11111111-1111-1111-1111-111111111111', 'נונה - הגננת', 'גן נונה בנונה', 'נ')
on conflict (id) do nothing;

on conflict (id) do nothing;

-- Notifications (broadcast) ------------------------------------------------
on conflict (id) do nothing;

-- Calendar events ----------------------------------------------------------
on conflict (id) do nothing;
